 1	import React from 'react';
 2	
 3	import { WizardTab } from '@catalog/wizard/tabs';
 4	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import EnvironmentForm from '@kubevirt-utils/components/EnvironmentEditor/EnvironmentForm';
 6	import Loading from '@kubevirt-utils/components/Loading/Loading';
 7	import SidebarEditor from '@kubevirt-utils/components/SidebarEditor/SidebarEditor';
 8	import { PATHS_TO_HIGHLIGHT } from '@kubevirt-utils/resources/vm/utils/constants';
 9	import { Bullseye, PageSection, PageSectionVariants } from '@patternfly/react-core';
10	
11	import './wizard-environment-tab.scss';
12	
13	const WizardEnvironmentTab: WizardTab = ({ updateVM, vm }) => {
14	  if (!vm)
15	    return (
16	      <Bullseye>
17	        <Loading />
18	      </Bullseye>
19	    );
20	
21	  return (
22	    <PageSection className="wizard-environment-tab" variant={PageSectionVariants.light}>
23	      <SidebarEditor<V1VirtualMachine>
24	        onResourceUpdate={updateVM}
25	        pathsToHighlight={PATHS_TO_HIGHLIGHT.ENV_TAB}
26	        resource={vm}
27	      >
28	        <EnvironmentForm updateVM={updateVM} vm={vm} />
29	      </SidebarEditor>
30	    </PageSection>
31	  );
32	};
33	
34	export default WizardEnvironmentTab;

